// Updated ComplianceDashboard.jsx
// Dropdown-driven Store & Employee Compliance Dashboard (Minimal Sidebar)

import React, { useState, useEffect } from 'react';
import { Card, Row, Col, Badge, ProgressBar, Alert } from 'react-bootstrap';
import {
  FileText,
  Users,
  Store,
  CheckCircle,
  XCircle,
  AlertTriangle,
  TrendingUp,
  AlertCircle,
  Clock,
  Target,
  ChevronDown,
  ChevronRight
} from 'lucide-react';
import { searchDocuments } from '../api';
import './ComplianceDashboard.css';

const ComplianceDashboard = () => {
  const [loading, setLoading] = useState(true);
  const [selectedStore, setSelectedStore] = useState(null);
  const [selectedEmployee, setSelectedEmployee] = useState(null);
  const [showStoreDropdown, setShowStoreDropdown] = useState(false);
  const [showEmployeeDropdown, setShowEmployeeDropdown] = useState(false);

  const [dashboardData, setDashboardData] = useState({
    totalDocuments: 0,
    validDocuments: 0,
    expiringDocuments: 0,
    expiredDocuments: 0,
    missingDocuments: 0,
    totalEmployees: 0,
    employeesWithCompleteDocuments: 0,
    employeesWithPendingDocuments: 0,
    storeWiseData: [],
    employeeWiseData: [],
    complianceRate: 0
  });

  const employeeStoreMapping = [
    { id: 'EMP001', name: 'Rajesh Kumar', store: 'Station Alpha' },
    { id: 'EMP002', name: 'Priya Singh', store: 'Station Beta' },
    { id: 'EMP003', name: 'Amit Patel', store: 'Station Gamma' },
    { id: 'EMP004', name: 'Sneha Reddy', store: 'Station Delta' },
    { id: 'EMP005', name: 'Vikram Sharma', store: 'Station Epsilon' },
    { id: 'EMP006', name: 'Anita Desai', store: 'Station Zeta' },
    { id: 'EMP007', name: 'Rahul Mehta', store: 'Station Eta' },
    { id: 'EMP008', name: 'Kavita Joshi', store: 'Station Theta' },
    { id: 'EMP009', name: 'Suresh Nair', store: 'Station Iota' },
    { id: 'EMP010', name: 'Meera Nair', store: 'Station Kappa' }
  ];

  const mandatoryDocuments = [
    'ID Proof',
    'Address Proof',
    'Educational Certificate',
    'Employment Contract'
  ];

  useEffect(() => {
    loadDashboardData();
  }, []);

  const getStatusColor = (expiryDate) => {
    if (!expiryDate) return 'valid';
    const today = new Date();
    const expiry = new Date(expiryDate);
    const diff = Math.floor((expiry - today) / (1000 * 60 * 60 * 24));
    if (diff <= 0) return 'expired';
    if (diff <= 30) return 'expiring';
    return 'valid';
  };

  const loadDashboardData = async () => {
    setLoading(true);
    try {
      const response = await searchDocuments({});
      const docs = response?.data?.data || [];

      const enriched = docs.map(doc => {
        const emp = employeeStoreMapping.find(e => e.id === doc.employeeId);
        return {
          ...doc,
          employeeName: emp?.name || 'Unknown',
          store: emp?.store || 'Unknown',
          status: getStatusColor(doc.expiryDate)
        };
      });

      const employeeMap = {};

      enriched.forEach(doc => {
        if (!employeeMap[doc.employeeId]) {
          employeeMap[doc.employeeId] = {
            employeeId: doc.employeeId,
            employeeName: doc.employeeName,
            store: doc.store,
            totalDocs: 0,
            validDocs: 0,
            expiringDocs: 0,
            expiredDocs: 0,
            mandatoryDocs: new Set()
          };
        }

        const emp = employeeMap[doc.employeeId];
        emp.totalDocs++;
        if (doc.status === 'valid') emp.validDocs++;
        if (doc.status === 'expiring') emp.expiringDocs++;
        if (doc.status === 'expired') emp.expiredDocs++;
        if (mandatoryDocuments.includes(doc.documentType)) {
          emp.mandatoryDocs.add(doc.documentType);
        }
      });

      employeeStoreMapping.forEach(emp => {
        if (!employeeMap[emp.id]) {
          employeeMap[emp.id] = {
            employeeId: emp.id,
            employeeName: emp.name,
            store: emp.store,
            totalDocs: 0,
            validDocs: 0,
            expiringDocs: 0,
            expiredDocs: 0,
            mandatoryDocs: new Set()
          };
        }
      });

      const employeeWiseData = Object.values(employeeMap).map(emp => {
        const missingMandatory = mandatoryDocuments.filter(
          d => !emp.mandatoryDocs.has(d)
        );
        return { ...emp, missingMandatory };
      });

      const totalDocuments = enriched.length;
      const validDocuments = enriched.filter(d => d.status === 'valid').length;
      const expiringDocuments = enriched.filter(d => d.status === 'expiring').length;
      const expiredDocuments = enriched.filter(d => d.status === 'expired').length;

      const missingDocuments = employeeWiseData.reduce(
        (sum, e) => sum + e.missingMandatory.length,
        0
      );

      const employeesWithCompleteDocuments = employeeWiseData.filter(
        e => e.missingMandatory.length === 0 && e.expiredDocs === 0
      ).length;

      setDashboardData({
        totalDocuments,
        validDocuments,
        expiringDocuments,
        expiredDocuments,
        missingDocuments,
        totalEmployees: employeeWiseData.length,
        employeesWithCompleteDocuments,
        employeesWithPendingDocuments: employeeWiseData.length - employeesWithCompleteDocuments,
        storeWiseData: [],
        employeeWiseData,
        complianceRate: totalDocuments ? Math.round((validDocuments / totalDocuments) * 100) : 0
      });
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="text-center py-5">Loading dashboard…</div>;
  }

  return (
    <div className="compliance-dashboard-wrapper">
      {/* Minimal Sidebar */}
      <div className="compliance-sidebar-minimal">
        <button className="dropdown-trigger" onClick={() => setShowStoreDropdown(!showStoreDropdown)}>
          <Store size={18} /> Stores {showStoreDropdown ? <ChevronDown /> : <ChevronRight />}
        </button>
        {showStoreDropdown && dashboardData.employeeWiseData
          .reduce((acc, e) => acc.add(e.store), new Set())
          && [...new Set(dashboardData.employeeWiseData.map(e => e.store))].map(store => (
            <div key={store} className="dropdown-item-custom" onClick={() => {
              setSelectedStore(store);
              setSelectedEmployee(null);
            }}>{store}</div>
          ))}

        <button className="dropdown-trigger mt-3" onClick={() => setShowEmployeeDropdown(!showEmployeeDropdown)}>
          <Users size={18} /> Employees {showEmployeeDropdown ? <ChevronDown /> : <ChevronRight />}
        </button>
        {showEmployeeDropdown && dashboardData.employeeWiseData.map(emp => (
          <div key={emp.employeeId} className="dropdown-item-custom" onClick={() => {
            setSelectedEmployee(emp);
            setSelectedStore(emp.store);
          }}>{emp.employeeName}</div>
        ))}
      </div>

      {/* Main Content */}
      <div className="compliance-content">
        <Card className="mb-4 shadow-sm">
          <Card.Header className="bg-gradient-primary text-white">
            <h4><Target size={22} className="me-2" />Overall Compliance Dashboard</h4>
          </Card.Header>
        </Card>

        {dashboardData.expiredDocuments > 0 && (
          <Alert variant="danger"><XCircle size={16} /> {dashboardData.expiredDocuments} documents expired</Alert>
        )}

        {dashboardData.missingDocuments > 0 && (
          <Alert variant="warning"><AlertTriangle size={16} /> {dashboardData.missingDocuments} mandatory documents missing</Alert>
        )}

        {/* Dynamic View */}
        <Card className="shadow-sm">
          <Card.Body>
            {!selectedStore && !selectedEmployee && (
              <div className="text-muted text-center py-4">Select Store or Employee from sidebar</div>
            )}

            {selectedStore && !selectedEmployee && (
              <Row>
                {dashboardData.employeeWiseData.filter(e => e.store === selectedStore).map(emp => (
                  <Col md={4} key={emp.employeeId}>
                    <Card className="mb-3 shadow-sm">
                      <Card.Body>
                        <strong>{emp.employeeName}</strong>
                        <div className="small text-muted">Missing: {emp.missingMandatory.length}</div>
                      </Card.Body>
                    </Card>
                  </Col>
                ))}
              </Row>
            )}

            {selectedEmployee && (
              <div>
                <h5>{selectedEmployee.employeeName}</h5>
                <p className="text-muted">{selectedEmployee.store}</p>
                <ul>
                  {selectedEmployee.missingMandatory.length === 0
                    ? <li className="text-success">All mandatory documents uploaded</li>
                    : selectedEmployee.missingMandatory.map((d, i) => <li key={i} className="text-danger">{d}</li>)}
                </ul>
              </div>
            )}
          </Card.Body>
        </Card>
      </div>
    </div>
  );
};

export default ComplianceDashboard;
